import{_ as r,o as i,c as s,a2 as e,j as o}from"./chunks/framework.DpbdyYUv.js";const m=JSON.parse('{"title":"Placa de desarrollo PULSAR C6","description":"","frontmatter":{},"headers":[],"relativePath":"pulsar-c6-getting-started/00_about.md","filePath":"pulsar-c6-getting-started/00_about.md"}'),t={name:"pulsar-c6-getting-started/00_about.md"};function l(n,a,d,c,u,p){return i(),s("div",null,[...a[0]||(a[0]=[e('<h1 id="placa-de-desarrollo-pulsar-c6" tabindex="-1">Placa de desarrollo PULSAR C6 <a class="header-anchor" href="#placa-de-desarrollo-pulsar-c6" aria-label="Permalink to &quot;Placa de desarrollo PULSAR C6&quot;">​</a></h1><h2 id="introduccion" tabindex="-1">Introducción <a class="header-anchor" href="#introduccion" aria-label="Permalink to &quot;Introducción&quot;">​</a></h2><p>Esta guía te ayudará a comenzar con la placa de desarrollo <strong>PULSAR C6</strong>. La <strong>PULSAR C6</strong> está basada en el microcontrolador ESP32C6 y está diseñada para prototipado y desarrollo de aplicaciones IoT. La placa incluye varias interfaces, como GPIO, I2C, SPI, UART y otras, además de soporte integrado para Wi-Fi y Bluetooth.</p><blockquote><p>Placa de desarrollo <strong>PULSAR C6</strong></p></blockquote><h2 id="microcontrolador-esp32c6" tabindex="-1">Microcontrolador ESP32C6 <a class="header-anchor" href="#microcontrolador-esp32c6" aria-label="Permalink to &quot;Microcontrolador ESP32C6&quot;">​</a></h2><p>El ESP32-C6 es un microcontrolador versátil de consumo ultra bajo, con conectividad avanzada y periféricos integrados. Es adecuado para una amplia variedad de aplicaciones IoT y sistemas embebidos.</p>',6),o("div",{style:{"text-align":"center"}},[o("button",{style:{"background-color":"#87cefa",color:"white",border:"none",padding:"10px 20px"},onclick:"window.open('https://www.espressif.com/sites/default/files/documentation/esp32-c6_datasheet_en.pdf', '_blank')"},"Hoja de datos ESP32C6")],-1),e('<h3 id="arquitectura" tabindex="-1">Arquitectura <a class="header-anchor" href="#arquitectura" aria-label="Permalink to &quot;Arquitectura&quot;">​</a></h3><ul><li><strong>Arquitectura de CPU</strong>: <ul><li>Basada en la <strong>ISA RISC-V de 32 bits</strong>.</li><li>Incluye: <ul><li>Una <strong>CPU de alto rendimiento (HP)</strong> de hasta <strong>160 MHz</strong> con pipeline de 4 etapas.</li><li>Una <strong>CPU de bajo consumo (LP)</strong> de hasta <strong>20 MHz</strong> para tareas energéticamente eficientes.</li></ul></li></ul></li><li><strong>Memoria</strong>: <ul><li><strong>320 KB de ROM</strong> para arranque y funciones esenciales.</li><li><strong>512 KB de SRAM de alto rendimiento</strong> (HP SRAM) para datos e instrucciones.</li><li><strong>16 KB de SRAM de bajo consumo</strong> (LP SRAM), con retención de datos durante modos de suspensión.</li><li>Soporte opcional para flash y SRAM externas mediante SPI, Dual SPI, Quad SPI y QPI.</li></ul></li><li><strong>Características de seguridad</strong>: <ul><li>Arranque seguro y cifrado de memoria.</li><li>Aceleradores criptográficos por hardware para AES, RSA, SHA, ECC y HMAC.</li><li>Soporte para entorno de ejecución confiable (TEE).</li></ul></li><li><strong>Capacidades inalámbricas</strong>: <ul><li><strong>Wi-Fi 6 (2.4 GHz)</strong>, Bluetooth 5.3, Zigbee y Thread (802.15.4) para opciones de conectividad versátiles.</li><li>Coexistencia integrada para operación simultánea de Wi-Fi, Bluetooth y 802.15.4.</li></ul></li></ul><h3 id="caracteristicas-generales" tabindex="-1">Características generales <a class="header-anchor" href="#caracteristicas-generales" aria-label="Permalink to &quot;Características generales&quot;">​</a></h3><ul><li><strong>GPIO y funcionalidad de E/S</strong>: <ul><li>Hasta <strong>30 GPIO</strong> (QFN40) o <strong>22 GPIO</strong> (QFN32).</li><li>Múltiples funciones de E/S mediante multiplexado de pines.</li><li>Soporte para configuraciones digitales y analógicas: <ul><li><strong>ADC SAR de 12 bits</strong> con hasta 7 canales.</li><li><strong>Sensor de temperatura</strong> integrado.</li></ul></li></ul></li><li><strong>Interfaces periféricas</strong>: <ul><li>Interfaces digitales: <ul><li>Dos <strong>UART</strong>.</li><li><strong>I2C</strong> e <strong>I2S</strong> para comunicación y procesamiento de audio.</li><li><strong>SPI</strong> con múltiples modos para transferencia rápida de datos.</li></ul></li><li>Controladores PWM: <ul><li><strong>LED PWM</strong> con hasta 6 canales.</li><li><strong>PWM para control de motor (MCPWM)</strong> para control de precisión.</li></ul></li><li><strong>Contador de pulsos</strong> para medición de frecuencia y señales.</li><li><strong>Controlador USB Serial/JTAG</strong> para depuración y comunicación serie.</li></ul></li><li><strong>Temporizadores</strong>: <ul><li><strong>Temporizador de sistema de 52 bits</strong> para medición precisa de tiempo.</li><li>Dos <strong>temporizadores de propósito general de 54 bits</strong>.</li><li>Múltiples <strong>watchdogs digitales</strong> para confiabilidad.</li></ul></li></ul><h3 id="gestion-de-energia" tabindex="-1">Gestión de energía <a class="header-anchor" href="#gestion-de-energia" aria-label="Permalink to &quot;Gestión de energía&quot;">​</a></h3><ul><li>Soporta cuatro modos de energía para optimizar el consumo: <ul><li><strong>Active</strong>, <strong>Modem-sleep</strong>, <strong>Light-sleep</strong>, and <strong>Deep-sleep</strong>.</li></ul></li><li>Consumo ultra bajo en <strong>modo Deep-sleep</strong> (7 µA).</li><li>Conserva memoria y funciones críticas en modos de bajo consumo.</li></ul><h3 id="seguridad-y-aceleracion-por-hardware" tabindex="-1">Seguridad y aceleración por hardware <a class="header-anchor" href="#seguridad-y-aceleracion-por-hardware" aria-label="Permalink to &quot;Seguridad y aceleración por hardware&quot;">​</a></h3><ul><li><strong>Controlador DMA general</strong> para transferencias de datos eficientes.</li><li>Aceleradores criptográficos por hardware integrados: <ul><li><strong>AES</strong>, <strong>RSA</strong>, <strong>SHA</strong>, and <strong>ECC</strong>.</li></ul></li><li>Arranque seguro y cifrado de flash para integridad del sistema.</li></ul><h3 id="aplicaciones" tabindex="-1">Aplicaciones <a class="header-anchor" href="#aplicaciones" aria-label="Permalink to &quot;Aplicaciones&quot;">​</a></h3><p>El ESP32-C6 es ideal para diversas aplicaciones, incluyendo:</p><ul><li>Dispositivos de hogar inteligente.</li><li>Automatización industrial.</li><li>Concentradores de sensores IoT y registradores de datos.</li><li>Electrónica de consumo y otras aplicaciones.</li></ul><h3 id="soporte-de-desarrollo" tabindex="-1">Soporte de desarrollo <a class="header-anchor" href="#soporte-de-desarrollo" aria-label="Permalink to &quot;Soporte de desarrollo&quot;">​</a></h3><ul><li>Totalmente compatible con <strong>ESP-IDF</strong> de Espressif (IoT Development Framework) para desarrollo profesional.</li><li>Soporte para <strong>Arduino IDE</strong> para aficionados y tareas de programación más simples.</li><li>Compatibilidad con SDK de terceros para integrarse en distintos flujos de trabajo.</li></ul><h3 id="dimensiones-fisicas" tabindex="-1">Dimensiones físicas <a class="header-anchor" href="#dimensiones-fisicas" aria-label="Permalink to &quot;Dimensiones físicas&quot;">​</a></h3><ul><li><strong>Formato compacto</strong> adecuado para aplicaciones embebidas.</li><li>Disponible en encapsulados QFN40 (5×5 mm) y QFN32 (5×5 mm), lo que ofrece versatilidad para distintos diseños.</li></ul><div class="caution"><div class="title"><p>Precaución</p></div><p>Estas son especificaciones generales; según el fabricante y el módulo ESP32-C6 específico, pueden existir diferencias en características o capacidades adicionales.</p></div>',16)])])}const h=r(t,[["render",l]]);export{m as __pageData,h as default};
